Theorem not_iso_RennerD51 : isopres RennerD51_Gay not_RennerD51 -> False.
Proof.
move=> isoRennerD51.
have {}: isopres RennerD51_Gay_rws not_RennerD51_rws.
  apply: (isopres_trans (isopres_sym isopres_RennerD51_Gay)).
  exact: (isopres_trans isoRennerD51 isopres_not_RennerD51).
evar (rew_RennerD51 : word int -> option (word int)).
have rew_RennerD51P : rewrites1_Ok (prelat RennerD51_Gay_rws) rew_RennerD51.
  exact: (trie_rewrites1P (trielen := 12)).
evar (rew_not_RennerD51 : word int -> option (word int)).
have rew_not_RennerD51P : rewrites1_Ok (prelat not_RennerD51_rws) rew_not_RennerD51.
  exact: (trie_rewrites1P (trielen := 12)).
apply: (size_non_isopres rew_RennerD51P rew_not_RennerD51P
          RennerD51_Gay_rws_convergent not_RennerD51_rws_convergent
          (boundP := 37) (boundQ := 21)).
- by native_cast_no_check is_true_true.
- rewrite ltnNge -flatten_is_longerE.
  by native_cast_no_check is_true_true.
Time Qed.
